class Solution:
    def isDiffChars(self, s1, k1, s2, k2, S, n):
        frequencyMap = {}
        for i in range(n):
            char = S[i]
            frequencyMap[char] = frequencyMap.get(char, 0) + 1

        for i in range(k1):
            char = s1[i]
            frequencyMap[char] -= 1

        for i in range(k2):
            char = s2[i]
            frequencyMap[char] -= 1

        diff = 0
        for i in range(n):
            char = S[i]
            if(char not in frequencyMap or frequencyMap[char] != 0):
                diff++

        return diff > 0

    def minDistance(self, S, k1, k2):
        n = len(S)
        minimumDistance = float('inf')
        for i in range(n - k1 + 1):
            for j in range(i + k1, n + 1 - k2):
                if(self.isDiffChars(s1, k1, s2, k2, S[i:i + k1], n - i - k1 + 1) and self.isDiffChars(s2, k2, s1, k1, S[j:j + k2], n - j - k2 + 1) and i + k1 - j - k2 + 1 < minimumDistance):
                    minimumDistance = i + k1 - j - k2 + 1

        return minimumDistance

