// -*- C++ -*-
#include <iostream>
#include <string>
#include <vector>
#include <unordered_map>

using namespace std;

class Solution {
public:
int minDistance(string S, int k1, int k2) {
    int n = S.size();
    int minimumDistance = INT_MAX;
    for(int i = 0; i <= n - k1; i++) {
        for(int j = i + k1; j <= n - k2; j++) {
            if(isDiffChars(S.substr(i, k1).c_str(), k1, S.substr(j, k2).c_str(), k2, S.c_str(), n) && i + k1 - j - k2 + 1 < minimumDistance) {
                minimumDistance = i + k1 - j - k2 + 1;
            }
        }
    }
    return minimumDistance;
}

bool isDiffChars(const char s1[], int k1, const char s2[], int k2, const char S[], int n) {
    unordered_map<char, int> frequencyMap;
    for(int i = 0; i < n; i++) {
        char charS = S[i];
        frequencyMap[charS] = frequencyMap.count(charS) ? frequencyMap[charS] + 1 : 1;
    }

    for(int i = 0; i < k1; i++) {
        char charS1 = s1[i];
        --frequencyMap[charS1];
    }

    for(int i = 0; i < k2; i++) {
        char charS2 = s2[i];
        --frequencyMap[charS2];
    }

    int diff = 0;
    for(int i = 0; i < n; i++) {
        char charS = S[i];
        if(!frequencyMap.count(charS) || frequencyMap[charS] != 0) {
            ++diff;
        }
    }

    return diff > 0;
}
};

int main() {
    Solution sol;
    string S;
    cin >> S;
    int k1, k2;
    cin >> k1 >> k2;
    int n = S.size();
    int min_distance = sol.minDistance(S, k1, k2);
    cout << min_distance << endl;
    return 0;
}
